	private static VarConstant varConstant(Var var, ValueConstant constant, Map<String, Integer> slots) {
		Integer slot = slots.get(var.getName());
		if (slot == null) {
			return null;
		}
		return new VarConstant(slot, constant.getValue());
	}

	private static Long resolveId(Value value, Function<Value, Long> valueIds) {
		if (valueIds == null) {
			return null;
		}
		return valueIds.apply(value);
	}

	private static Boolean embeddedBoolean(Literal literal) {
		try {
			CoreDatatype.XSD datatype = literal.getCoreDatatype().asXSDDatatypeOrNull();
			return datatype == CoreDatatype.XSD.BOOLEAN ? literal.booleanValue() : null;
		} catch (IllegalArgumentException e) {
			return null;
		}
	}

	private static Long embeddedInteger(Literal literal) {
		try {
			if (literal.getCoreDatatype().isXSDDatatype()
					&& literal.getCoreDatatype().asXSDDatatypeOrNull().isIntegerDatatype()) {
				return literal.longValue();
			}
			return null;
		} catch (IllegalArgumentException e) {
			return null;
		}
	}

