	private static String generatedIntegerCompare(String lhsVariable, Compare.CompareOp operator, long rhs) {
		return switch (operator) {
		case EQ -> lhsVariable + " == " + rhs + "L";
		case NE -> lhsVariable + " != " + rhs + "L";
		case LT -> lhsVariable + " < " + rhs + "L";
		case LE -> lhsVariable + " <= " + rhs + "L";
		case GT -> lhsVariable + " > " + rhs + "L";
		case GE -> lhsVariable + " >= " + rhs + "L";
		};
	}

	private static long decodeIntegerIdValue(int type, long encoded) {
		if (type == ValueIds.T_BYTE) {
			return (byte) encoded;
		}
		if (type == ValueIds.T_UNSIGNEDBYTE) {
			return encoded;
		}
		return (encoded >>> 1) ^ -(encoded & 1L);
	}

